#include "udp_comm.h"
#include <WiFi.h>
#include <WiFiUdp.h>
static WiFiUDP udp;
static uint16_t _port=0;
void udp_setup(uint16_t p){_port=p;udp.begin(p);Serial.printf("[udp] OK port=%d\n",p);}
void udp_loop(){}
bool udp_send(const char*h,uint16_t p,const char*m){udp.beginPacket(h,p);udp.print(m);return udp.endPacket();}
String udp_receive(){int sz=udp.parsePacket();if(!sz)return"";char buf[256];int n=udp.read(buf,255);buf[n]=0;return String(buf);}
